```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Convert records to the appropriate format for insertion
  std::vector<std::vector<std::optional<std::string>>> formatted_records;
  for (const auto& record : records) {
    std::vector<std::optional<std::string>> row;
    // Assuming T has fields that can be converted to optional strings
    // This would need to be adapted based on the actual table structure
    row.push_back(std::to_string(record.SNo.value())); // Example for PrimaryKey
    row.push_back(record.SName.value()); // Example for Varchar
    row.push_back(record.Sex ? "1" : "0"); // Example for int
    // Add other fields as needed...
    formatted_records.push_back(std::move(row));
  }

  // Perform the insertion
  auto result = sqlgen::insert(conn, formatted_records);
  if (!result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Determine the primary key column name based on table
  std::string primary_key_col;
  if (table_name == "Student") {
    primary_key_col = "SNo";
  } else if (table_name == "Course") {
    primary_key_col = "CID";
  } else if (table_name == "Score") {
    primary_key_col = "ScID";
  } else if (table_name == "Major") {
    primary_key_col = "MID";
  } else {
    throw std::invalid_argument("Invalid table name");
  }

  // Construct and execute the delete statement
  auto delete_stmt = sqlgen::delete_from<TableType> | where(primary_key_col == record_id);
  auto result = delete_stmt(conn);
  if (!result) {
    throw std::runtime_error("Failed to delete record");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Determine the table type based on table name
  using TableType;
  if (table_name == "Student") {
    using TableType = Student;
  } else if (table_name == "Course") {
    using TableType = Course;
  } else if (table_name == "Score") {
    using TableType = Score;
  } else if (table_name == "Major") {
    using TableType = Major;
  } else {
    throw std::invalid_argument("Invalid table name");
  }

  // Determine the primary key column name
  std::string primary_key_col;
  if constexpr (std::is_same_v<TableType, Student>) {
    primary_key_col = "SNo";
  } else if constexpr (std::is_same_v<TableType, Course>) {
    primary_key_col = "CID";
  } else if constexpr (std::is_same_v<TableType, Score>) {
    primary_key_col = "ScID";
  } else if constexpr (std::is_same_v<TableType, Major>) {
    primary_key_col = "MID";
  }

  // Construct and execute the update statement
  auto update_stmt = sqlgen::update<TableType>(set(col_name) = new_value) | where(primary_key_col == record_id);
  auto result = update_stmt(conn);
  if (!result) {
    throw std::runtime_error("Failed to update record");
  }
}
```

**Note:** This implementation assumes that:
1. The table names correspond to the struct names in `eas_common.hpp`
2. The primary key column names are known for each table
3. The `new_value` can be converted to a string representation suitable for SQL
4. Error handling is done through exceptions

The code uses sqlgen's fluent API to construct SQL statements and executes them against the database connection. The `delete_from` and `update` functions utilize the `where` clause to filter by the primary key ID, and the `insert` function handles the bulk insertion of records.

Please note that this implementation may need adjustments based on the exact structure of your tables and the specific requirements of your application.

