    }
    auto conn = conn_result.value();

    // Create Product table with IF NOT EXISTS logic
    auto create_table_stmt = sqlgen::create_table<Product> | sqlgen::if_not_exists;
    auto result = create_table_stmt(*conn);
    if (!result) {
      return false;
    }

    // Create standard index on category with IF NOT EXISTS
    using namespace sqlgen::literals;
    auto idx_category = sqlgen::create_index<"idx_product_category", Product>("category"_c) | sqlgen::if_not_exists;
    result = idx_category(*conn);
    if (!result) {
      return false;
    }

    // Create unique index on sku with IF NOT EXISTS
    auto idx_sku = sqlgen::create_index<"idx_product_sku", Product>("sku"_c) | sqlgen::if_not_exists;
    // Note: The reference materials don't show a unique modifier, 
