    // For a proper implementation, there should be a unique_index function or modifier
    // This is a simplified version based on available materials
    auto idx_sku_obj = sqlgen::create_index<"idx_product_sku", Product>("sku"_c);
    idx_sku_obj.unique_ = true;
    idx_sku_obj.if_not_exists_ = true;
