```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create select query from Source with value field
    auto select_query = sqlgen::select_from<Source>("value"_c);

    // Apply where condition (value > 100)
    auto filtered_query = select_query | sqlgen::where("value"_c > 100);

    // Create table Target from the select query
    auto create_query = sqlgen::create_as<Target>(filtered_query);

    return create_query;
}

}  // namespace create_table_as_select
```

**Explanation of the implementation:**

1. **`using namespace sqlgen::literals;`** - Enables the use of the `_c` literal suffix for column names
2. **`sqlgen::select_from<Source>("value"_c)`** - Creates a SELECT query from the Source table, selecting only the "value" column
3. **`select_query | sqlgen::where("value"_c > 100)`** - Applies the WHERE condition using the pipe operator as shown in the reference materials
4. **`sqlgen::create_as<Target>(filtered_query)`** - Creates a CREATE TABLE AS SELECT statement targeting the Target structure
5. **Return type** - The function returns the query object as specified in the requirements

